"""
MKT Christ Commentary — Joshua chapters 15–17
Run: python3 scripts/zc-christ-joshua-15-17-fill.py

Key decisions:
- Ch 15: Judah's territory treated as the land of the Messiah — its geography is
  the geography of Christ's birth, ministry, death, and resurrection.
  V.8 Ben-hinnom Valley = Gehenna; v.63 Jerusalem Jebusites = shadow of the cross.
  Town-list verses use brief theme/shadow entries linking Judah's inheritance
  to the messianic line and NT geography.
- Ch 16: Ephraim (Joshua's tribe) shadows Christ as the deliverer-figure from
  this territory; Gezer's non-expulsion as the pattern of incomplete faith.
- Ch 17: Zelophehad's daughters as type of all who inherit through faith regardless
  of typical social exclusion; Joseph's complaint as the pattern of faith-failure
  even in the midst of God's provision.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOSHUA = {
  "15": {
    "1": '<p>A theme: Judah receives the first and largest tribal allotment. The pre-eminence of Judah in the distribution is the territorial expression of Jacob\'s blessing — "the scepter shall not depart from Judah" (Gen 49:10). The land being divided here is the land from which the Messiah will come; every city name in ch.15 will be, in some sense, a city in the landscape of Christ\'s story.</p>',
    "2": '<p>A theme: the southern boundary of Judah begins at the Dead Sea — the lowest point on earth, the end of the Arabah rift valley. The geography of death (the Dead Sea\'s salt and barrenness) forms the outer boundary of the inheritance given to the tribe of the Messiah. Christ will descend to the lowest point — "he descended into the lower parts of the earth" (Eph 4:9) — so that his ascent fills all things.</p>',
    "3": '<p>A theme: the southern boundary passes Kadesh-barnea — the site of Israel\'s greatest failure (Num 13-14). That the place of rebellion is now part of Judah\'s boundary is a quiet indication that the judgment of the wilderness generation does not permanently define the land. The inheritance overrides the memory of failure.</p>',
    "4": '<p>A theme: the Wadi of Egypt (Brook of Egypt) marks the southwestern boundary — the traditional border between Canaan and Egypt. The inheritance of Judah extends from the edge of Egypt westward to the Mediterranean. Christ who was taken to Egypt as a child (Matt 2:13-15) and called out of Egypt (Matt 2:15, quoting Hos 11:1) moves along the same geographic axis.</p>',
    "5": '<p>A theme: the eastern boundary is the Dead Sea and the Jordan\'s mouth. The Jordan is where Jesus was baptized (Matt 3:13-17), beginning his public ministry in the tribal territories whose boundaries run along this river. The sacred geography of the boundaries is the backdrop for the sacred geography of the gospel.</p>',
    "6": '<p>A theme: Beth-arabah (House of the Arabah) and the Stone of Bohan mark the northern boundary of Judah near Jericho. Jericho is the city through which Jesus passes on his way to Jerusalem (Luke 18:35; 19:1) — the geographical threshold between wilderness and city, between the Jordan crossing and the final ascent to the cross.</p>',
    "7": '<p>A theme: the Valley of Achor (trouble/distress) is specifically named in Isa 65:10 and Hos 2:15 as a place that will be transformed — the valley of trouble will become a door of hope. The boundary of Judah runs through the place of covenant failure (Achan\'s sin, Josh 7) and the prophetic promise of its reversal: the geography of judgment becomes the boundary of hope.</p>',
    "8": '<p>A direct reference: the boundary runs through the Valley of Ben-hinnom (<em>Ge-Ben-Hinnom</em>) to the south of Jerusalem. This valley — where child sacrifice to Molech was later practiced (2 Kgs 23:10; Jer 7:31) and where the city\'s refuse was burned — became the NT\'s word for hell: Gehenna (<em>Ge-Hinnom</em>). The valley of fire at Jerusalem\'s south wall is the geography behind Jesus\'s warnings about hell (Matt 5:22; 18:9; Mark 9:43-48).</p>',
    "9": '<p>A theme: the boundary passes the spring of Nephtoah (possibly Lifta, northwest of Jerusalem) and toward the towns of Mount Ephron. The spring imagery runs through Judah\'s boundaries: springs of water mark the land as alive, not dead. Christ offers the ultimate spring — "whoever drinks the water I give him will never be thirsty again" (John 4:14).</p>',
    "10": '<p>A theme: Mount Seir and Mount Jearim (Chesalon) on the border route. The "bare mountain" geography recalls the wilderness and the exposed places where Israel was tested. The mountains of Judah\'s territory include those of barrenness and those of promise — the full spectrum of the human experience Christ entered by being born into this geography.</p>',
    "11": '<p>A theme: the boundary runs to Ekron, one of the five Philistine cities. The Philistine cities were the persistent thorn in Judah\'s side throughout the period of the judges and early monarchy. Christ will be born in the very territory that was most contested — "he came to his own, and his own did not receive him" (John 1:11). The Messiah enters the most disputed geography.</p>',
    "12": '<p>A theme: the Mediterranean ("Great Sea") as the western boundary — the sea as the limit of the land. In Revelation\'s new creation, "the sea was no more" (Rev 21:1). The boundary of Judah\'s inheritance against the sea anticipates the new creation where all geographic limits are dissolved in Christ\'s reign.</p>',
    "13": '<p>A type: Caleb receives Hebron within Judah\'s territory "in keeping with the LORD\'s command to Joshua." The YHWH-commanded allocation to a faithful individual within the larger tribal grant foreshadows the NT principle of reward for faithfulness — crowns and specific responsibilities given to those who served well (Matt 25:21; 1 Cor 3:12-15). Covenant faithfulness is honored with a specific, personal inheritance.</p>',
    "14": '<p>A theme: Caleb drives out the three Anakite sons — Sheshai, Ahiman, Talmai — the very descendants of Anak whose presence at Hebron had caused the ten spies to despair (Num 13:22). What once produced paralyzing fear is now defeated by a man of faith at 85. This is the pattern of NT courage: "I can do all things through Christ who strengthens me" (Phil 4:13).</p>',
    "15": '<p>A theme: from Hebron, Caleb advances against Debir (Kiriath-sepher, "city of the book/writing"). The conquest of the city of writing is a striking detail in a book that repeatedly emphasizes the keeping and teaching of the Torah (1:8). The inheritance of the word-city points to Christ as the Word (<em>Logos</em>) who takes possession of the domain of meaning (John 1:1-4).</p>',
    "16": '<p>A type: Caleb\'s offer — whoever captures Kiriath-sepher wins Achsah as a wife. The warrior-prize-bride pattern appears throughout the ancient world and in the gospels in the parable of the wedding banquet (Matt 22:1-14). The bridegroom who wins the battle wins the bride; the pattern prefigures Christ who "loved the church and gave himself up for her" to win the bride (Eph 5:25-27).</p>',
    "17": '<p>A type: Othniel son of Kenaz, Caleb\'s younger brother, takes Kiriath-sepher and receives Achsah. Othniel becomes the first judge of Israel (Judg 3:9-11) — the deliverer-figure who foreshadows Christ as the ultimate deliverer. His qualification for leadership is demonstrated in this conquest; those who serve faithfully in smaller assignments are entrusted with greater ones (Luke 16:10).</p>',
    "18": '<p>A revelation of God: Achsah asks her father for a field and, arriving at his home, asks further for springs of water. The daughter\'s boldness in approaching her father for more of the inheritance — first a field, then water — is a model of the NT\'s invitation to ask boldly: "Ask and it will be given to you" (Matt 7:7). The Father gives more to those who ask; the dry southern land is not the limit of the inheritance.</p>',
    "19": '<p>A revelation of God: Caleb gives Achsah both upper and lower springs. The provision of both springs — comprehensive, not minimal — reflects the divine character of generosity: "he who did not spare his own Son but gave him up for us all, how will he not also with him graciously give us all things?" (Rom 8:32). The generous father giving water to the asking daughter is an image of the heavenly Father.</p>',
    "20": '<p>A theme: the formal summary — "this was the inheritance of the tribe of Judah according to their clans." The word <em>nachala</em> (inheritance) carries the weight of both legal title and covenant promise. The NT applies the inheritance language to believers in Christ: "heirs of God and fellow heirs with Christ" (Rom 8:17). Judah\'s territorial inheritance is the physical shadow of the spiritual inheritance secured through the Son of Judah.</p>',
    "21": '<p>A theme: the town lists of vv.21-62 catalog the specific settlements within Judah\'s territory by geographic district. Each town represents a human community in the land of the Messiah\'s ancestry. Kabzeel ("God gathers") and the southern towns are in the area of David\'s early life and refuge — the land of future-king formation. The geography of the lists is the geography of redemption history.</p>',
    "22": '<p>A theme: Kinah, Dimonah, Adadah — small towns in the Negev district. Dinah (a variant spelling) and similar names reflect the settled life of pastoral communities. Even the smallest and least-known towns in Judah\'s inheritance are named and remembered — a reflection of the divine attention to every particular within the covenant people\'s life.</p>',
    "23": '<p>A theme: Kedesh in the Negev (different from Kedesh in Galilee) and Hazor — the common name "Hazor" (enclosure/settlement) reflects a landscape of established communities. The Negev towns formed the boundary communities between Judah and the wilderness, the settled and the desert, the inheritance and the not-yet-claimed.</p>',
    "24": '<p>A theme: Ziph — a town that later becomes significant in David\'s story as the area where he hid from Saul (1 Sam 23:14; 26:1-2) and where the Ziphites betrayed him to Saul. The landscapes of the ancestor David\'s suffering and flight are simultaneously the landscapes of his kingdom — and of his greater Son\'s own suffering in the same region.</p>',
    "25": '<p>A theme: Hazor-hadattah (New Hazor) and Kerioth-hezron. Kerioth appears again in connection with Judas Iscariot — "Iscariot" likely means "man from Kerioth." If this identification is correct, Judas\'s ancestral town is in the heart of Judah\'s southern district — the one who betrayed the Son of Judah came from Judah\'s own territory.</p>',
    "26": '<p>A theme: Amam, Shema, Moladah — Moladah means "birth/generation." The place of birth is in the southern district of the tribe of the Messiah. The specific attention to towns named for birth and lineage (<em>moladah</em>) in the genealogical register of Judah\'s land points to the tribe through which the Messiah enters history by birth.</p>',
    "27": '<p>A theme: Hazar-gaddah (Settlement of Fortune), Heshmon, Beth-pelet (House of Escape/Refuge). The names in Judah\'s town register encode the theological vocabulary of the covenant: settlement, provision, and refuge. Beth-pelet as "house of escape" anticipates Christ who is the ultimate refuge — "a refuge from the storm" (Isa 25:4).</p>',
    "28": '<p>A theme: Beersheba — the Well of the Oath, where Abraham made a covenant with Abimelech (Gen 21:31) and where Isaac encountered YHWH (Gen 26:23-25). The inclusion of this patriarchal covenant site within Judah\'s inheritance shows how the tribal boundaries enclose the covenant memories of the fathers. Christ is the fulfillment of every oath sworn at Beersheba.</p>',
    "29": '<p>A theme: Baalah (another name for Kiriath-jearim), Iim, Ezem — Baalah/Kiriath-jearim was where the ark rested for twenty years after being returned by the Philistines (1 Sam 7:1-2) and from where David brought it to Jerusalem (2 Sam 6:2). The ark\'s resting place in Judah\'s territory points to Christ as the presence of God dwelling within the covenant people.</p>',
    "30": '<p>A theme: Eltolad, Chesil, Hormah — Hormah (devoted to destruction) appears here as one of the inherited towns. The town whose name means destruction is given to Judah as a settled inheritance. What was cursed becomes the covenant community\'s possession — the same pattern as the cross, where what looks like destruction is the location of redemption.</p>',
    "31": '<p>A theme: Ziklag — later given to David by Achish king of Gath (1 Sam 27:6) and the site of the Amalekite raid during which David recovered his people and the spoil (1 Sam 30). Ziklag is one of the places in Judah\'s land most associated with David\'s hardship and his demonstration of YHWH-dependent courage — qualities the greater Son of David will embody fully.</p>',
    "32": '<p>A theme: Ain and Rimmon (later merged as En-Rimmon, Neh 11:29) in the Negev district. Rimmon means pomegranate, a fruit associated in Song of Songs with the beloved (Song 4:3, 13). The towns of the bride\'s imagery (Judah\'s inheritance) are the geographic setting for the OT love poetry that the NT reads as the story of Christ and the church (Eph 5:25-27).</p>',
    "33": '<p>A theme: the Shephelah (lowland foothills) district opens with Eshtaol and Zorah. Samson\'s home was between Zorah and Eshtaol (Judg 13:25; 16:31) — the lowland terrain that produced one of the most complex deliverer-figures in the OT. The Shephelah towns of Judah are the towns of deliverers, echoing the pattern of the ultimate deliverer who will come from Judah\'s line.</p>',
    "34": '<p>A theme: Zanoah, En-gannim, Tappuah, Enam — "spring of gardens" (En-gannim) and Tappuah (apple tree) evoke the Garden imagery of Song of Songs and Eden. The Shephelah towns with agricultural names point to the land as a place of fruitfulness — the fruitfulness that Christ restores when he says "I am the true vine" (John 15:1).</p>',
    "35": '<p>A theme: Jarmuth, Adullam, Socoh, Azekah — Adullam is the cave where David gathered his 400 distressed and discontented men (1 Sam 22:1-2), and Socoh-Azekah is the valley of Elah where David killed Goliath (1 Sam 17:1). The geography of Judah\'s Shephelah is the geography of David\'s defining moments — and therefore the geography from which Christ\'s ancestral story draws its deepest patterns.</p>',
    "36": '<p>A theme: Shaaraim (two gates), Adithaim, Gederah — Shaaraim appears in the Goliath story (1 Sam 17:52) as the road of Philistine flight after David\'s victory. The two-gated city on the boundary of David\'s victory is a geographic marker of the turning point in Israel\'s history — when the giant falls, the direction of the story changes permanently.</p>',
    "37": '<p>A theme: Zenan, Hadashah (new), Migdal-gad (tower of fortune) — the name "Hadashah" (new) appears in a list of old Canaanite towns that have been given to Judah. The new name anticipates the "new thing" that YHWH will do (Isa 43:19) and the "new creation" in Christ (2 Cor 5:17). Old towns receive new identity under covenant ownership.</p>',
    "38": '<p>A theme: Mizpeh (watchtower/lookout) in the Shephelah — different from the northern Mizpeh of Benjamin. The name reflects Israel\'s pattern of building places of watchfulness throughout the land. The NT equivalent is the church\'s calling to "be watchful, stand firm in the faith" (1 Cor 16:13) — the covenant community as watchmen in the inheritance.</p>',
    "39": '<p>A theme: Lachish — one of the most strategic cities of the Shephelah, seat of a southern Canaanite king (Josh 12:11). Lachish later becomes a key Assyrian target in Sennacherib\'s 701 BCE campaign (2 Kgs 18:14; 19:8; Isa 36-37), and its siege is depicted on Assyrian palace reliefs. The city that Judah inherited eventually falls under judgment — a reminder that the land inheritance could be lost through the same unfaithfulness that cost the wilderness generation their portion.</p>',
    "40": '<p>A theme: Cabbon, Lahmas, Kithlish — the cluster of smaller towns in the Shephelah hills. These communities represent the dense network of settled life that Judah\'s inheritance supports. The covenant people\'s inheritance is not a wilderness but a populated, cultivated, settled land — an image of the "rest" that Hebrews 4 describes as the believer\'s goal in Christ.</p>',
    "41": '<p>A theme: Gederoth, Beth-dagon (house of Dagon — the Philistine grain god), Naamah (pleasant), Makkedah — Beth-dagon in Judah\'s inheritance is named after a Philistine deity. The inclusion of a Baal/Dagon-named town in the covenant people\'s inheritance reflects the persistent presence of Canaanite religious culture within the land. The struggle against idolatry within the inheritance anticipates the NT\'s warning: "flee from idolatry" (1 Cor 10:14).</p>',
    "42": '<p>A theme: Libnah (white/luminous) — the city later associated with a rebellion against the apostate king Jehoram (2 Kgs 8:22). The city of brightness in Judah\'s inheritance has a history of resistance to covenant infidelity. Libnah\'s later stand against apostasy prefigures the remnant principle: within the inheritance, there are always those who refuse to abandon the covenant.</p>',
    "43": '<p>A theme: Iphtah, Ashnah (second), Nezib (garrison/pillar) — garrison towns in the Shephelah protecting the highlands. The protective character of the boundary towns reflects the covenant community\'s calling to be a shield for the sacred center. The structure of Judah\'s territory — boundary towns protecting inner communities — mirrors the NT\'s teaching about spiritual warfare protecting the church\'s core (Eph 6:10-18).</p>',
    "44": '<p>A theme: Keilah, Achzib (deception/lie), Mareshah — Keilah was where David rescued the Gadites from the Philistines (1 Sam 23:1-5), then nearly betrayed by the Keilahites themselves (1 Sam 23:12). Mareshah was the birthplace of Micah the prophet (Mic 1:1, 15). The towns of Judah\'s inheritance include both the places of David\'s loyalty and the places of prophetic proclamation.</p>',
    "45": '<p>A theme: Ekron — the northernmost Philistine city, formally included in Judah\'s ideal allotment though never controlled. The Philistine cities within Judah\'s stated boundary represent the persistent gap between the promised inheritance and the actual possession — the "already but not yet" tension that Hebrews 4 and Romans 8 develop as the condition of the church in the present age.</p>',
    "46": '<p>A theme: from Ekron to the sea — the Philistine coastal plain between Judah\'s hills and the Mediterranean. The coastal towns near Ashdod represent the Philistine presence that Israel failed to remove. The sea coast remains outside effective Israelite control, a standing reminder of incomplete faithfulness — and the territory through which the gospel will eventually travel westward (Acts 8:26-40, Philip and the Ethiopian eunuch on the Gaza road).</p>',
    "47": '<p>A theme: Ashdod and Gaza — the two southernmost Philistine cities on the coast. Gaza is where Samson was imprisoned (Judg 16:21) and destroyed the Philistine temple (Judg 16:29-30); it is also the starting point of the Ethiopian eunuch\'s road (Acts 8:26). The Philistine cities within Judah\'s boundary become NT mission waypoints — the inheritance is progressively claimed through the proclamation of the gospel.</p>',
    "48": '<p>A theme: the hill country district opens — Shamir, Jattir, Socoh (different from the Shephelah Socoh). The Judean highlands are the core of the tribal inheritance, the uplands where David\'s kingdom will be centered and where the Jerusalem temple will be built. The hill country is the place of encounter with YHWH throughout Israel\'s history, from Abraham\'s altar at Shechem to Solomon\'s temple on Zion.</p>',
    "49": '<p>A theme: Debir (Kiriath-sannah / Kiriath-sepher, "city of writing") appears again in the hill country list. As the city of the scribal tradition, Debir in Judah\'s highland represents the place where the word is preserved and transmitted. The hill country of Judah is where the literary tradition of Israel — the Torah, the Psalms, the Prophets — is primarily produced and maintained.</p>',
    "50": '<p>A theme: Anab (grape cluster), Eshtemoh (hearing), Anim — grape-cluster imagery evokes the two scouts who carried the cluster of grapes from Eshcol (Num 13:23), the first fruit of the land, back to the wilderness generation. The hill country towns with harvest names represent the fruitfulness of the covenant land. Christ is the true vine who produces the fruit of the new creation (John 15:5).</p>',
    "51": '<p>A theme: Goshen (different from Egypt\'s Goshen), Holon, Giloh — Giloh was the home of Ahithophel, David\'s advisor who betrayed him (2 Sam 15:12; 23:34) — the same pattern as Judas Iscariot. The town of the betrayer is within the inheritance of Judah. Both the line of blessing and the line of betrayal run through Judah\'s geography.</p>',
    "52": '<p>A theme: Arab, Dumah (silence/stillness), Eshan — Dumah appears in Isa 21:11 as a name for Edom and a place of prophetic silence. The name of silence within Judah\'s hill country inheritance points to the silent Thursday night before the crucifixion, the silence of the tomb, and the stillness from which resurrection speaks. The covenant geography includes the geography of silent waiting.</p>',
    "53": '<p>A theme: Janum, Beth-tappuah (house of the apple), Aphekah — Tappuah (apple) imagery recurs in Song of Songs 2:3 ("Like an apple tree among the trees of the forest is my beloved"). The apple-house in Judah\'s hill country is a geographic echo of the vineyard and orchard imagery that the prophets use for Israel\'s covenant relationship with YHWH and that the NT develops as the church\'s union with Christ.</p>',
    "54": '<p>A theme: Humtah, Kiriath-arba (Hebron) — the second appearance of Hebron in the chapter. Hebron was the city where Abraham purchased his burial cave (Gen 23), where the patriarchs were buried, where David was first anointed king (2 Sam 2:4), and where Caleb received his inheritance. The city of beginnings and covenants appears twice in Judah\'s register because its significance cannot be reduced to a single mention.</p>',
    "55": '<p>A theme: Maon, Carmel (garden/orchard), Ziph, Juttah — Maon and Ziph are both associated with David\'s years as a fugitive from Saul (1 Sam 23:24-25; 26:2-3). The hills of Maon and Ziph are where David learned to trust YHWH in the wilderness of persecution — the years that formed the "man after God\'s own heart" who was an ancestor of Christ. The geography of formation is in the heart of Judah\'s hill country.</p>',
    "56": '<p>A theme: Jezreel (God sows), Jokdeam, Zanoah — "God sows" as a town name within Judah\'s inheritance anticipates the sowing imagery of the NT parables (Matt 13:3-23). The name Jezreel appears again in Hos 2:22 as an eschatological promise of divine sowing in the restored covenant. The hill country of Judah is the sowed ground from which the Messiah grows.</p>',
    "57": '<p>A theme: Kain, Gibeah (Hill), Timnah — Gibeah in the hill country of Judah (not the Gibeah of Benjamin) is another hill-town. The hills of Judah — the landscape of shepherd-life, of cave-refuge, of watchman towers — are the landscape Christ inhabits in the parables of the good shepherd (John 10) and the lost sheep (Luke 15:3-7).</p>',
    "58": '<p>A theme: Beth-zur (house of the rock), Gedor — Beth-zur was a significant Maccabean fortress (1 Macc 4:29, 61; 6:7), and Gedor is mentioned in 1 Chr 4:39 in connection with Simeonite expansion. The rock-house in Judah\'s hill country names the theological vocabulary of Ps 18:2 ("the LORD is my rock, my fortress") and Christ\'s foundational metaphor in Matt 7:24-25: building on the rock.</p>',
    "59": '<p>A theme: Maarath (bare place), Beth-anoth (house of echoes/answers), Eltekon — bare places and answering places within Judah\'s territory. The stripped, bare places (Maarath) are the places of wilderness within the settled land; the answering place (Beth-anoth) is where prayer returns. The covenant land contains both the wilderness-test and the answered-prayer within its boundaries — the full range of the spiritual life.</p>',
    "60": '<p>A theme: Kiriath-baal (Kiriath-jearim, city of forests) and Rabbah. Kiriath-jearim was the ark\'s resting place after the Philistine return (1 Sam 7:1-2) and the starting point of David\'s processional (2 Sam 6:2). The ark — the symbol of God\'s presence dwelling with his people — rested twenty years at Kiriath-jearim within Judah\'s territory. The geography of the ark\'s rest is the geography of divine presence awaiting its permanent home.</p>',
    "61": '<p>A theme: the wilderness district — Beth-arabah, Middin, Secacah — the barren eastern slope of the Judean hills descending to the Dead Sea. This terrain includes the Judean desert where John the Baptist will preach (Matt 3:1-3) and where Jesus will be tempted (Matt 4:1-11). The wilderness towns at the edge of Judah\'s territory are the landscape of prophetic formation and messianic testing.</p>',
    "62": '<p>A theme: En-gedi (spring of the young goat) — the oasis on the western shore of the Dead Sea where David hid from Saul in the caves (1 Sam 23:29; 24:1). En-gedi means "spring of the kid" and was associated with henna blossoms in Song of Songs 1:14. The place of the beloved\'s spring and the place of the covenant king\'s refuge in the wilderness are one and the same — the geography of Judah contains both the Song and the story.</p>',
    "63": '<p>A shadow: "the Israelites could not drive out the Jebusites who lived in Jerusalem. To this day the Jebusites live among Judah in Jerusalem." Jerusalem — the city of the Messiah\'s death, resurrection, and Pentecost — is not yet fully Israel\'s. The city where Christ will be crucified, buried, and risen remains in other hands throughout the period of the judges. The incomplete possession of Jerusalem is the most freighted unfinished-conquest note in the book: the most important city in the story of salvation remains un-claimed until David takes it (2 Sam 5:6-9).</p>'
  },
  "16": {
    "1": '<p>A theme: the allotment for the Joseph tribes begins at the Jordan near Jericho — the city of the first conquest and the gateway to the land. Jericho\'s springs are specifically mentioned: the first city conquered opens into water and life, not just military possession. Christ\'s baptism in the Jordan and his passage through Jericho on the way to Jerusalem (Luke 19:1) follows the same geographic axis as Joseph\'s inheritance-entry.</p>',
    "2": '<p>A theme: Bethel (house of God) marks the boundary of Joseph\'s territory. Bethel was where Jacob saw the heavenly ladder (Gen 28:10-22) — the vision of a stairway between heaven and earth, which Christ applies to himself in John 1:51 ("you will see heaven opened and the angels of God ascending and descending on the Son of Man"). The house of God on Jacob\'s boundary is the place where heaven touches earth — a geographic marker of the incarnation\'s trajectory.</p>',
    "3": '<p>A theme: Lower Beth-horon and Gezer mark the western limit of Joseph\'s territory. Beth-horon (house of the hollow) was the site of one of Joshua\'s great victories — the long-day battle (Josh 10:10-14). The geography of miraculous victory frames the western edge of the Joseph tribes\' inheritance: the place where the sun stood still for the sake of the covenant is the boundary of the promised land.</p>',
    "4": '<p>A theme: "So the descendants of Joseph — Manasseh and Ephraim — received their inheritance." The double portion of Joseph (through his two sons) reflects the birthright transferred from Reuben (1 Chr 5:1-2). The Joseph tribes receive more of the land because of their ancestor\'s faithfulness. The principle that greater faithfulness produces greater inheritance is also present in the NT parable of the talents (Matt 25:14-30).</p>',
    "5": '<p>A theme: Ephraim\'s border runs from Ataroth-addar eastward. Ephraim was the tribe of Joshua — the deliverer of Israel who led the conquest. The tribe whose territory is being described here produced the man under whose leadership the whole land was entered. Christ, the ultimate deliverer, is not from Ephraim but from Judah — yet the Joseph tradition of the double portion and the deliverer-figure enriches the messianic concept.</p>',
    "6": '<p>A theme: the northern boundary of Ephraim runs through Michmethath and Taanath-shiloh toward Janoah. Michmethath appears also in the Manasseh boundary (17:7) — a shared landmark that required both tribes to negotiate their boundary carefully. The careful delineation of the tribal boundaries reflects the covenant principle that each family\'s inheritance is specific and inviolable — a foretaste of the individual accountability before God (2 Cor 5:10).</p>',
    "7": '<p>A theme: from Janoah down to Ataroth and Naarah (young girl/maiden) to Jericho and the Jordan. Naarah as a place name within the inheritance territory echoes the cultural significance of daughters within the covenant community — a significance dramatized in Zelophehad\'s daughters (ch.17) and in the NT\'s Galatians 3:28 declaration that there is neither male nor female in Christ.</p>',
    "8": '<p>A theme: the Kanah Ravine as the western boundary of Ephraim, ending at the sea. The ravine (deep cleft) as a boundary marker separates Ephraim from Manasseh\'s territory to the north. The boundary ravines of the Joseph tribes become significant in later prophetic texts: Zech 14:4-5 describes the Mount of Olives splitting into a great valley at the Day of the LORD — the geography of boundaries transformed by divine presence.</p>',
    "9": '<p>A theme: "Some cities were set apart for Ephraim within the territory of Manasseh." The interdigitation of tribal territories — Ephraimite cities within Manasseh\'s land — reflects the practical complexity of family relationships within the covenant community. The messy overlap of human family claims is not an error in the divine plan but a reflection of the covenant community\'s organic, relational character.</p>',
    "10": '<p>A shadow: "the Ephraimites did not drive out the Canaanites living in Gezer." Gezer remained Canaanite until given to Solomon\'s wife as a dowry gift by her Pharaonic father (1 Kgs 9:16). The Ephraimite failure echoes the larger pattern: the inherited land always requires active faith to possess, and the failure to fully possess becomes a source of ongoing compromise. The NT parallel is the warning not to "make room for the devil" (Eph 4:27) — leaving spiritual footholds unclaimed is perpetually dangerous.</p>'
  },
  "17": {
    "1": '<p>A theme: Machir the firstborn of Manasseh, the father of Gilead, receives Gilead and Bashan because he was "a man of war." The warrior-inheritance pattern appears throughout Joshua: those who fought the LORD\'s battles receive specific portions of what they fought for. The NT principle is analogous: "We are more than conquerors through him who loved us" (Rom 8:37) — the spiritual inheritance is secured through the victory of Christ, not human effort, but it is entered through active faith.</p>',
    "2": '<p>A theme: the Manassite clans receive their portions — Abiezer, Helek, Asriel, Shechem, Hepher, Shemida. Shechem as a clan name appears in the territory that will include the city of Shechem — where Abraham first camped in Canaan (Gen 12:6), where Jacob bought land (Gen 33:18-20), and where Jesus met the Samaritan woman at Jacob\'s well (John 4:4-6). The inheritance allotment plants the covenant community in the geography of patriarchal encounter.</p>',
    "3": '<p>A type: Zelophehad had no sons but five daughters — Mahlah, Noah, Hoglah, Milcah, and Tirzah — who had already received a ruling from Moses (Num 27:1-11). The case of Zelophehad\'s daughters is the OT\'s landmark inheritance case for women: the principle that daughters inherit when there are no sons was explicitly legislated by YHWH. This legal provision anticipates the NT\'s radical inclusion: in Christ, the inheritance belongs to all who are in him regardless of social position (Gal 3:28-29).</p>',
    "4": '<p>A type: "They appeared before Eleazar the priest, Joshua son of Nun, and the leaders, saying, \'The LORD commanded Moses to give us an inheritance among our brothers.\'" The daughters\' appeal to Moses\'s prior command — to the Word of God as the ground of their claim — is the model of NT faith: claiming the inheritance on the basis of what God has spoken, not on social convention or personal merit. "The scripture cannot be broken" (John 10:35) is the same logic applied to every divine promise.</p>',
    "5": '<p>A theme: Manasseh receives ten portions total — five for the male clans plus five for Zelophehad\'s daughters (the daughters effectively double one clan\'s count). The larger inheritance comes precisely through the provision for those who would otherwise be excluded. The expansion of the inheritance through inclusion is the NT pattern: the ingrafted Gentiles do not diminish the Jewish inheritance but increase the whole (Rom 11:12).</p>',
    "6": '<p>A revelation of God: "Manasseh\'s daughters inherited among his sons. The rest of Manasseh\'s sons had the land of Gilead." The daughters inherit <em>among</em> the sons — not instead of, but equally with. This arrangement (anticipated by Moses, confirmed by Joshua, ratified by the community) is the OT\'s clearest statement of the principle of equal inheritance across gender lines. The NT\'s "neither male nor female" (Gal 3:28) does not create a new principle but declares the fulfillment of the principle YHWH established here.</p>',
    "7": '<p>A theme: Manasseh\'s southern boundary runs through Asher (different from the tribe Asher) to Michmethath east of Shechem. Shechem is in the center of the Joseph tribes\' territory — the city of covenants, from Abraham\'s first altar (Gen 12:6) through the great covenant renewal under Joshua (Josh 24). The Shechem-centered geography of the Joseph tribes frames the covenant-renewal purpose of the entire conquest.</p>',
    "8": '<p>A theme: the town of Tappuah belongs to Ephraim though the surrounding land is Manasseh\'s. The border town with divided ownership — the town in one tribe, the surrounding fields in another — is a practical reality of land tenure. The covenant community lives with the complexity of overlapping claims; the response is not conflict but careful adjudication under the law. The law\'s wisdom in handling ambiguous cases points to Christ as the one in whom all claims are finally resolved.</p>',
    "9": '<p>A theme: the Kanah Ravine forms the southern boundary of Manasseh, with Ephraimite cities within Manasseh\'s territory. The boundary description "these Ephraimite towns are within the territory of Manasseh" normalizes the complexity of inter-tribal land tenure. The Joseph tribes\' interdigitated territory models the NT church\'s complexity: people of different communities sharing life within each other\'s domains.</p>',
    "10": '<p>A theme: "The territory to the south was Ephraim\'s and to the north was Manasseh\'s." The Joseph tribes divide the central highlands of Canaan — the heartland of the promised land. The central position of the Joseph tribes (descended from Jacob\'s beloved son) in the geographic center of the inheritance reflects Joseph\'s typological significance: the suffering servant who becomes the provider-redeemer (Gen 45:7-8) who foreshadows Christ.</p>',
    "11": '<p>A theme: Manasseh holds Beth-shean, Ibleam, Dor, En-dor, Taanach, and Megiddo — "within the territory of Issachar and Asher." Megiddo is the plain of the great battles of history (Judg 5:19; 2 Kgs 23:29-30) — the geography behind Revelation\'s Armageddon (Rev 16:16). The final battle of history is named after a place in the inheritance of Manasseh; the geography of the end is within the geography of the covenant distribution.</p>',
    "12": '<p>A shadow: the Manassites were unable to drive out the inhabitants of those towns. The repeated failure to fully expel the Canaanites (16:10; 17:12) establishes a pattern that will define the book of Judges: the incomplete conquest produces the ongoing temptation to assimilate. The NT warns against the same pattern of spiritual compromise: "Do not be unequally yoked with unbelievers" (2 Cor 6:14) — the practical wisdom behind the conquest\'s call to full expulsion.</p>',
    "13": '<p>A shadow: when Israel grew stronger, they subjected the Canaanites to forced labor rather than expelling them. The substitution of economic exploitation for covenant obedience is a theological regression: YHWH commanded expulsion, not subjugation. The half-measure of making servants of those who should have been expelled becomes the context for the Judges cycles. The NT equivalent: tolerating ongoing sin rather than mortifying it (Rom 8:13; Col 3:5).</p>',
    "14": '<p>A revelation of God: the descendants of Joseph complain to Joshua — "why have you given us only one allotment and one portion? We are a great people, since YHWH has blessed us." The irony is sharp: they appeal to their greatness as a reason for receiving more while doing nothing to claim what they already have. The complaint of insufficient inheritance without faith-action to possess it is the pattern Jesus addresses: "To everyone who has, more will be given, but from the one who has not, even what he has will be taken away" (Matt 25:29).</p>',
    "15": '<p>A revelation of God: Joshua\'s reply — "if you are such a great people, go up into the forest and clear land there in the Perizzite and Rephaim land" — refuses to indulge the complaint. The inheritance is available but must be actively taken by clearing the forest. The Josephites have both the divine blessing and the human responsibility to act on it. The NT\'s "work out your own salvation with fear and trembling, for it is God who works in you" (Phil 2:12-13) combines the same divine gift and human effort.</p>',
    "16": '<p>A revelation of God: the Josephites counter that the hill country is not enough and the Canaanites in the valley have iron chariots. The complaint moves from "not enough land" to "the enemy is too powerful" — the same trajectory as the ten faithless spies at Kadesh. Iron chariots (<em>rechev barzel</em>) are treated as an insurmountable obstacle; but YHWH had promised that no enemy could stand against Israel (1:5). The same covenant promise that was sufficient at Jericho is sufficient against iron chariots.</p>',
    "17": '<p>A revelation of God: Joshua affirms both the greatness of the Joseph tribes and the expectation that they will prevail. "You are a great people and have great power" — the acknowledgment of their strength is real, not sarcastic. The greater the power, the greater the responsibility to use it in faith. The NT\'s principle is the same: "from everyone who has been given much, much will be demanded" (Luke 12:48). Divine blessing creates obligation, not exemption.</p>',
    "18": '<p>A revelation of God: "the forested hill country will be yours. Clear it, and it will be yours to its farthest limits. You will drive out the Canaanites, though they have iron chariots and though they are strong." The final word is a command of confidence: the iron-chariot problem is real but not final. The divine assurance overrides the military obstacle. This is the pattern of faith throughout Scripture: "The LORD your God who goes before you will himself fight for you" (Deut 1:30). What looks impossible to human assessment is possible with YHWH — the principle Christ confirms: "with God all things are possible" (Matt 19:26).</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'joshua')
    merge_comm(existing, JOSHUA)
    save_comm('mkt-christ', 'joshua', existing)
    print('Joshua 15-17 mkt-christ written.')

if __name__ == '__main__':
    main()
